// Public API Surface of message-server-components

import { ApplicationRef, NgZone, provideZonelessChangeDetection } from '@angular/core';
import { createCustomElement } from '@angular/elements';
import { FacebookLogin } from './components/facebook-login/facebook-login.component';
import { TemplateList } from './components/template-list/template-list.component';
import { TemplateEditor } from './components/editor/editor.component';
import { createApplication } from '@angular/platform-browser';
import { provideTranslateService } from '@ngx-translate/core';
import { provideHttpClient } from '@angular/common/http';

export * from './components/base.component';
export * from './components/editor/editor.component';
export * from './components/template-list/template-list.component';
export * from './components/facebook-login/facebook-login.component';
export type { TemplateData, Option } from './interfaces';

function registerElement(component: any, app: ApplicationRef) {
  if (!customElements.get(component.selector)) {
    customElements.define(component.selector, createCustomElement(component, { injector: app.injector }));
  }
}

export function setup ()  {
  (async () => {
    const app = await createApplication({
      providers: [
        provideZonelessChangeDetection(),
        provideHttpClient(),
        provideTranslateService({
          fallbackLang: 'en',
          lang: 'en'
        })
      ]
    });
    registerElement(TemplateEditor, app);
    registerElement(TemplateList, app);
    registerElement(FacebookLogin, app);
  })();
}