import { CommonModule } from '@angular/common';
import { Component, input } from '@angular/core';
import { Option } from "../../../interfaces";
import { TemplateData } from "../../../interfaces";
import { FormsModule } from '@angular/forms';
import { TranslateDirective, TranslatePipe } from '@ngx-translate/core';
import { MaxLengthDirective } from '../../maxLength.directive';
import { PlaceholderInsertPopover } from './placeholder-insert/placeholder-insert.directive';
import { ClearIcon } from '../../icons/clear-icon';
import { TooltipDirective } from "../../tooltip.directive";

@Component({
    selector: 'template-body',
    templateUrl: './body.part.html',
    styleUrls: ['../shared.scss'],
    imports: [CommonModule, FormsModule, TranslateDirective, TranslatePipe, MaxLengthDirective, PlaceholderInsertPopover, ClearIcon, TooltipDirective],
})
export class BodyPart {
    public readonly data = input.required<TemplateData>();
    public readonly options = input.required<Option[]>();

    public addButton() {
        if (!this.data().components.buttons) {
            this.data().components.buttons = { type: 'BUTTONS', buttons: [] };
        }
        if ((this.data().components.buttons!.buttons?.length ?? 0) >= 10) return;
        this.data().components.buttons!.buttons.push({ type: 'QUICK_REPLY', text: '' });
    }

    public removeButton(index: number) {
        const length = this.data().components.buttons?.buttons?.length ?? 0;
        if (!length || index < 0 || index >= length) return;

        this.data().components.buttons?.buttons.splice(index, 1);
    }

    public isUrlButtonTypeDisabled(index: number): boolean {
        const buttons = this.data().components.buttons?.buttons;;
        if (!buttons) return false;

        return !!buttons.find((b, i) => i !== index && b.type === 'URL');
    }
}