import { CommonModule } from "@angular/common";
import { Component, computed, DOCUMENT, effect, HostListener, inject, input, output, Renderer2, resource, signal, ViewEncapsulation } from "@angular/core";
import { FormsModule } from "@angular/forms";
import { TranslateDirective } from "@ngx-translate/core";
import { BaseComponent } from "../base.component";
import { HttpClient, HttpErrorResponse, HttpResponse } from "@angular/common/http";
import { Notification } from "../../interfaces";
import { SpinnerIcon } from "../icons/spinner-icon";

interface SignupMessage {
    phone_number_id: string;
    waba_id: string;
    business_id: string;
}

@Component({
    templateUrl: './facebook-login.component.html',
    styleUrls: ['./facebook-login.component.scss', '../buttons.scss', '../input.scss'],
    encapsulation: ViewEncapsulation.None,
    imports: [CommonModule, FormsModule, TranslateDirective, SpinnerIcon],
})
export class FacebookLogin extends BaseComponent {
    static override selector = 'vierkant-facebook-login';
    
    private readonly document = inject(DOCUMENT);
    private readonly http: HttpClient = inject(HttpClient);
    private readonly renderer = inject(Renderer2);
    private readonly COMPUTED_API_KEY = computed(() => this.API_KEY() ?? this.PROVIDED_API_KEY());
    private readonly facebookSDKInjected = signal<boolean>(false); 
    
    public readonly onSuccess = output<string | undefined>({alias: 'success'});
    public readonly onError = output<Notification>({alias: 'error'});

    public readonly APP_ID = input.required<string>();
    public readonly CONFIG_ID = input.required<string>();
    public readonly URL = input<string>("https://richarddev.vierkant.dev");
    public readonly PROVIDED_API_KEY = input<string>(undefined, { alias: 'API_KEY'});
    public readonly API_KEY = signal<string | undefined>(undefined);
    public readonly hasAPIKey = computed(() => !!this.COMPUTED_API_KEY());
    public readonly facebookButtonDisabled = signal(true);
    public readonly facebookState = signal<"default" | "loading">("loading");
    public readonly facebookResponse = signal<any>(null);
    public readonly facebookLoginAuthCode = signal<string | undefined>(undefined);

    public readonly facebookLoginToken = resource({
        defaultValue: undefined,
        params: () => ({
            authCode: this.facebookLoginAuthCode(),
            facebookResponse: this.facebookResponse(),
        }),
        loader: async ({params}) => {
            try {
                if (!params.authCode || !params.facebookResponse) return undefined;
                this.facebookState.set("loading");
                const result = await this.generateToken(params.authCode);
                if (result) this.onSuccess.emit(this.COMPUTED_API_KEY());
                return result;
            } catch (error) {
                if (error instanceof HttpErrorResponse) {
                    const errorDetail = error.error;
                    this.onError.emit({
                        severity: 'error',
                        summary: `${errorDetail.code || error.status}`,
                        detail: errorDetail.message || error.message || 'An error occurred',
                    });
                } else {
                    this.onError.emit({
                        severity: 'error',
                        summary: 'Facebook Login Error',
                        detail: (error as Error).message,
                    });
                }

                return undefined;            
            } finally {
                this.facebookButtonDisabled.set(false);
                this.facebookState.set("default");
            }
        }
    });
    
    private readonly window = this.document.defaultView as any;
    public get FB_SDK() {
        return this.window.FB;
    }
    
    @HostListener('window:message', ['$event'])
    onMessage(event: Event) {
        const messageEvent = event as MessageEvent;
        if (!['https://web.facebook.com', 'https://www.facebook.com'].includes(messageEvent.origin)) {
            console.warn('Origin mismatch:', messageEvent.origin);
            return;
        }
        try {
            if (typeof messageEvent.data !== 'string' || !messageEvent.data.startsWith('{')) return;
            const data = JSON.parse(messageEvent.data);
            switch (data.event) {
                case 'FINISH': this.facebookResponse.set(data.data); break;
                case 'CANCEL': this.facebookButtonDisabled.set(false); break;
                case 'ERROR': {
                    this.onError.emit({
                        severity: 'error',
                        summary: 'Facebook SDK Error',
                        detail: data.data?.message || 'An error occurred',
                    }); 
                    this.facebookButtonDisabled.set(false);
                    break
                };
            }
        } catch (err) {
            // Log unexpected errors for debugging
            console.error('Error handling message event:', err, event);
            this.onError.emit({
                severity: 'error',
                summary: 'Message Error',
                detail: (err as Error).message,
            });
        }
    }
    
    constructor() {
        super();
        effect(() => {
            if (this.hasAPIKey()) {
                this.facebookButtonDisabled.set(false);
            } else {
                this.facebookButtonDisabled.set(true);
            }
        });
    }
    
    async launchSignUp() {
        try {
            this.facebookButtonDisabled.set(true);
            const API_KEY = this.COMPUTED_API_KEY();
            console.log('Using API Key:', API_KEY);
            if (!API_KEY?.length) throw new Error("API Key is required");
            await new Promise((resolve, reject) => {
                this.http.get<SignupMessage>(`${this.URL()}/account/me`, { headers: this.getHeaders() }).subscribe({ next: (response: any) => {
                        console.log('Account info retrieved:', response);
                        resolve(true);
                    },
                    error: (error: HttpErrorResponse) => {
                        reject(error);
                    }
                });
            });
        } catch (error) {
            if (error instanceof HttpErrorResponse) {
                this.onError.emit({
                    severity: 'error',
                    summary: error.status.toString(),
                    detail: error.message,
                });
            }
            this.facebookButtonDisabled.set(false);
            this.facebookState.set("default");
            return;
        }
        
        this.injectFB_SDK();
        if (this.FB_SDK && 'login' in this.FB_SDK) {
            this.FB_SDK.logout(()=> {
                this.FB_SDK.login((response: any) => this.facebookLoginAuthCode.set(response.authResponse?.code), {
                    config_id: this.CONFIG_ID(),
                    response_type: 'code',
                    override_default_response_type: true,
                    extras: {"version":"v3",}
                });
                
            });
        } else {
            this.window.fbAsyncInit = () => {
                this.FB_SDK.init({
                    appId: this.APP_ID(),
                    autoLogAppEvents: true,
                    xfbml: false,
                    version: 'v24.0'
                });
                
                this.FB_SDK.login((response: any) => this.facebookLoginAuthCode.set(response.authResponse?.code), {
                    config_id: this.CONFIG_ID(),
                    response_type: 'code',
                    override_default_response_type: true,
                    extras: {"version":"v3",}
                });
            };
            
        }
    }
    
    private getHeaders(headers?: Record<string, string>): Record<string, string> {
        const API_KEY = this.COMPUTED_API_KEY();
        if (!API_KEY?.length) throw new Error("API Key is required");
        return {
            ...headers,
            'x-api-key': API_KEY,
        };
    }
    
    private injectFB_SDK() {
        if (this.facebookSDKInjected()) return;
        if(this.FB_SDK){
            this.facebookSDKInjected.set(true);
            return;
        }
        
        const script = this.renderer.createElement('script');
        script.src = "https://connect.facebook.net/en_US/sdk.js";
        script.async = true;
        script.defer = true;
        script.crossOrigin = "anonymous";
        this.renderer.appendChild(this.document.body, script);
    }
    
    private async generateToken(code: any) {
        const data = this.facebookResponse();
        if (!data) {
            throw new Error("No Facebook response data available");
        }
        const params = new URLSearchParams({
            code: code ?? '',
            phone: data.phone_number_id ?? '',
            account: data.waba_id ?? ''
        });

        return await new Promise<string>((resolve, reject) => {
           this.http.get<string>(`${this.URL()}/integrations/whatsapp/token?${params.toString()}`, { headers: this.getHeaders() }).subscribe({
                next: (response: string) => {
                    resolve(response);
                },
                error: (error: HttpErrorResponse) => reject(error)
            });
        });
        //
    }
}

