import { CommonModule } from '@angular/common';
import { Component, input, output, inject, computed } from '@angular/core';
import { TemplateData } from "../../../interfaces";
import { FormsModule } from '@angular/forms';
import { TranslateDirective } from '@ngx-translate/core';

@Component({
    selector: 'template-footer',
    templateUrl: './footer.part.html',
    styleUrls: ['../shared.scss'],
    imports: [CommonModule, FormsModule, TranslateDirective],
})
export class FooterPart {

    public readonly data = input.required<TemplateData>();
    public readonly onCancel = output<Event>({ alias: 'cancel' });
    public readonly onSave = output<Event>({ alias: 'save' });

    
    
    cancel($event: Event) {
        this.onCancel.emit($event);
    }
    
    save($event: Event) {
        this.onSave.emit($event);
    }
    
    public get error() {
        const {category, language} = this.data();
        const {body, header, footer} = this.data().components;
        const error: string[] = [];
        if (body?.text?.trim().endsWith('}}')) {
            error.push("ERROR.BODY.ENDS_WITH_PLACEHOLDER");
        }

        if (header?.text?.trim().endsWith('}}')) {
            error.push("ERROR.HEADER.ENDS_WITH_PLACEHOLDER");
        }
        
        if (footer?.text?.trim().endsWith('}}')) {
            error.push("ERROR.FOOTER.ENDS_WITH_PLACEHOLDER");
        }

        return error.length ? error : null;
    }
    
    public get isInvalid() {
        if (this.error?.length) return true;
        
        const {category, language} = this.data();
        if (category == null || category.trim() === '') return true;
        if (language == null || language.trim() === '') return true;

        const {body, buttons} = this.data().components;
        if (!body || body.text == null || body.text.trim() === '') return true;
        if (this.data().name == null || this.data().name.trim() === '') return true;
        if ((buttons?.buttons ?? []).length > 10) return true;
        if (buttons?.buttons.find(x => {
            if (x.type === 'QUICK_REPLY') return x.text?.trim().length === 0;
            if (x.type === 'URL') return x.example?.trim().length === 0 || x.url?.trim().length === 0;
            if (x.type === 'PHONE_NUMBER') return x.text?.trim().length === 0 || x.phone_number?.trim().length === 0;
            if (x.type === 'COPY_CODE') return x.example?.trim().length === 0;
            return false;
        })) return true;
        if ((buttons?.buttons ?? []).filter(x => x.type === 'URL').length > 1) return true;
        return false;
    }
}