import { Directive, ElementRef, Renderer2, OnDestroy, inject, signal, effect, ViewContainerRef, ComponentRef, input, HostListener } from '@angular/core';
import { PlaceholderInsertComponent } from './placeholder-insert.component';
import { Option } from "../../../../interfaces";

@Directive({
    selector: '[placeholderInsert]',
})
export class PlaceholderInsertPopover implements OnDestroy {

    private componentRef: ComponentRef<PlaceholderInsertComponent> | null = null;
    private readonly el = inject(ElementRef);
    private readonly renderer = inject(Renderer2);
    private readonly viewContainerRef = inject(ViewContainerRef);
    
    private readonly isFocused = signal(false);
    private unlistenFocus?: () => void;
    private unlistenBlur?: () => void;
    private unlistenPopoverMousedown?: () => void;
    private unlistenScroll?: () => void;
    private unlistenResize?: () => void;
    private unlistenPopoverFocusOut?: () => void;

    @HostListener('keyup.esc')
    protected onEscape() {
        this.removePopover();
    }


    public placeholderOptions = input.required<Option[]>({alias: 'placeholderInsert'});

    constructor() {
        effect(() => {
            const options = this.placeholderOptions();
            if (options.length === 0) 
                return;

            if (this.isFocused()) {
                this.createPopover();
            } else {
                this.removePopover();
            }
        });

        effect(() => {
            const options = this.placeholderOptions();
            if (this.componentRef) {
                this.componentRef.setInput('options', options);
            }
        });

        this.unlistenFocus = this.renderer.listen(this.el.nativeElement, 'focus', () => {
            this.isFocused.set(true);
        });

        this.unlistenBlur = this.renderer.listen(this.el.nativeElement, 'blur', (e: FocusEvent) => {
            const popover = this.componentRef?.location.nativeElement;
            if (popover?.contains(e.relatedTarget as Node)) {
                return;
            }
            this.isFocused.set(false);
        });
    }

    private createPopover() {
        if (this.componentRef) return;

        this.componentRef = this.viewContainerRef.createComponent(PlaceholderInsertComponent);
        this.componentRef.setInput('targetInput', this.el.nativeElement as HTMLInputElement | HTMLTextAreaElement);
        this.componentRef.setInput('options', this.placeholderOptions())
        const element = this.componentRef.location.nativeElement as HTMLElement;
        
        this.renderer.addClass(element, 'placeholder-popover');
        
        // this.unlistenPopoverMousedown = this.renderer.listen(element, 'mousedown', (e: Event) => {
        //     e.preventDefault();
        // });

        this.unlistenPopoverFocusOut = this.renderer.listen(element, 'focusout', (e: FocusEvent) => {
            const related = e.relatedTarget as Node;
            if (related !== this.el.nativeElement && !element.contains(related)) {
                this.isFocused.set(false);
            }
        });

        this.updatePosition();

        this.unlistenScroll = this.renderer.listen('window', 'scroll', () => this.updatePosition());
        this.unlistenResize = this.renderer.listen('window', 'resize', () => this.updatePosition());
    }

    private updatePosition() {
        if (!this.componentRef) return;
        const element = this.componentRef.location.nativeElement as HTMLElement;
        const inputRect = this.el.nativeElement.getBoundingClientRect();
        
        let top = inputRect.bottom;
        let left = inputRect.left;
        
        top += 10;
        left += 4;

        this.renderer.setStyle(element, 'top', `${top}px`);
        this.renderer.setStyle(element, 'left', `${left}px`);
    }

    private removePopover() {
        if (this.unlistenPopoverMousedown) {
            this.unlistenPopoverMousedown();
            this.unlistenPopoverMousedown = undefined;
        }
        if (this.unlistenPopoverFocusOut) {
            this.unlistenPopoverFocusOut();
            this.unlistenPopoverFocusOut = undefined;
        }
        if (this.unlistenScroll) {
            this.unlistenScroll();
            this.unlistenScroll = undefined;
        }
        if (this.unlistenResize) {
            this.unlistenResize();
            this.unlistenResize = undefined;
        }
        if (this.componentRef) {
            this.componentRef.destroy();
            this.componentRef = null;
        }
    }

    ngOnDestroy() {
        this.removePopover();
        this.unlistenFocus?.();
        this.unlistenBlur?.();
    }
}
