import { CommonModule } from "@angular/common";
import { Component, ViewEncapsulation, computed, input, output, signal } from "@angular/core";
import { BaseComponent } from "../base.component";
import { TemplateData } from "../../interfaces";
import { sortBy } from "../editor/util";
import { TranslateDirective, TranslatePipe } from "@ngx-translate/core";
import { FormsModule } from "@angular/forms";
import { ClearIcon } from "../icons/clear-icon";
import { EditIcon } from "../icons/edit-icon";

@Component({
    templateUrl: './template-list.component.html',
    styleUrls: ['./template-list.component.scss', '../buttons.scss', '../input.scss', '../editor/shared.scss'],
    encapsulation: ViewEncapsulation.None,
    imports: [CommonModule, FormsModule, TranslateDirective, TranslatePipe, ClearIcon, EditIcon],
})
export class TemplateList extends BaseComponent {
    static override selector = 'vierkant-template-list';
    public readonly filter = signal<string>('');
    public readonly data = input<TemplateData[], TemplateData[]>([], {
        transform: (value) => sortBy(value, t => t.name, t => t.language, t => t.category, t => t.status)
    });

    public readonly filteredData = computed(() => {
        const filter = this.filter()?.toLowerCase() ?? '';
        const data = this.data();
        if (!filter.length) return data;
        return data.filter(t => t.name.toLowerCase().includes(filter));
    });
    
    public readonly onEdit = output<TemplateData>({alias: 'edit' });
    protected edit(template: TemplateData) {
        this.onEdit.emit(structuredClone(template));
    }

    public readonly qualitySeverity = (template: TemplateData) => {
        switch (template.quality) {
            case 'GREEN': return "success";
            case 'YELLOW': return "warning";
            case 'RED': return "error";
            default: return "secondary";
        }
    };
    
    public readonly statusSeverity = (template: TemplateData) => {
        switch (template.status) {
            case 'APPROVED': return "success";
            case 'REJECTED': return "danger";
            case 'PAUSED': return "warning";
            case 'PENDING': return "info";
            case 'DELETED': return "secondary";
            default: return "secondary";
        }
    };
}   