import { CommonModule } from '@angular/common';
import { Component, computed, inject, input, output } from '@angular/core';
import { TranslateDirective, TranslatePipe } from '@ngx-translate/core';
import { TemplateData } from "../../../interfaces";
import { FormsModule } from '@angular/forms';
import { ConfirmationService } from '../../confirmation/confirmation.service';
import { MaxLengthDirective } from '../../maxLength.directive';
import { TooltipDirective } from '../../tooltip.directive';
import { DeleteIcon } from "../../icons/delete-icon";

@Component({
    selector: 'template-header',
    templateUrl: './header.part.html',
    styleUrls: ['../shared.scss'],
    imports: [CommonModule, FormsModule, TranslatePipe, TranslateDirective, MaxLengthDirective, TooltipDirective, DeleteIcon],
})
export class HeaderPart {
    private readonly confirmationService = inject(ConfirmationService);
    public readonly data = input.required<TemplateData>();
    public readonly onDelete = output<Event>({ alias: 'delete' });

    public readonly categories = ['MARKETING', 'UTILITY'] as const;
    public readonly languages = ['en', 'de'] as const;

    public readonly isNew = computed(() => {
        return !this.data().id?.length;
    });

    public readonly quality = computed(() => {
        switch (this.data().quality) {
            case 'GREEN': return "high_quality";
            case 'YELLOW': return "medium_quality";
            case 'RED': return "low_quality";
            default: return "unknown";
        }
    })
    public readonly status = computed(() => {
        switch (this.data().status) {
            case 'APPROVED': return "approved";
            case 'REJECTED': return "rejected";
            case 'PAUSED': return "paused";
            case 'PENDING': return "pending";
            case 'DELETED': return "deleted";
            default: return "unknown";
        }
    });

    public readonly qualitySeverity = computed(() => {
        switch (this.quality()) {
            case 'high_quality': return "success";
            case 'medium_quality': return "warning";
            case 'low_quality': return "error";
            default: return "secondary";
        }
    });

    public readonly statusSeverity = computed(() => {
        switch (this.status()) {
            case 'approved': return "success";
            case 'rejected': return "danger";
            case 'paused': return "warning";
            case 'pending': return "info";
            case 'deleted': return "secondary";
            default: return "secondary";
        }
    });

    public readonly category = computed(() => {
        switch (this.data().category.toLowerCase()) {
            case 'marketing': return "TEMPLATE_EDITOR.CATEGORY.MARKETING";
            case 'utility': return "TEMPLATE_EDITOR.CATEGORY.UTILITY";
            default: return "TEMPLATE_EDITOR.CATEGORY.UNKNOWN";
        }
    });

    public readonly language = computed(() => {
        const [lang, region] = this.data().language.split('_');
        if (region === undefined) return lang.toUpperCase();
        else return `${lang.toUpperCase()} (${region.toUpperCase()})`;
    });

    delete($event: PointerEvent) {
        this.confirmationService.show({
            target: $event.currentTarget,
            message: 'TEMPLATE_EDITOR.CONFIRMATION.DELETE_TEMPLATE',
            confirmText: 'BUTTONS.CONFIRM',
            cancelText: 'BUTTONS.CANCEL',
            onConfirm: () => {
                this.onDelete.emit($event);
            }
        });
    }
}