import { Directive, effect, inject, input, Type } from '@angular/core';
import { TranslateService } from '@ngx-translate/core';
import translationsEN from '../i18n/en.json';
import translationsDE from '../i18n/de.json';

const DEFAULT_LANG = 'de'; // TODO: language switch in web component doesn't seem to work? 

// Type for components with a static selector property
export  interface ComponentWithSelector extends Type<BaseComponent> {
    // Static property on the constructor function
    selector: string;
}

@Directive({})
export abstract class BaseComponent {
    public readonly translate = inject(TranslateService);
    public readonly language = input<string, string | null>(DEFAULT_LANG, {transform: (value) => (value ?? DEFAULT_LANG).toLocaleLowerCase()});
    static selector: string;

    constructor() {
        this.translate.setTranslation('en', translationsEN)
        this.translate.setTranslation('de', translationsDE)
        this.translate.setFallbackLang(DEFAULT_LANG);
        effect(() => {
            const lang = this.language() ?? DEFAULT_LANG;
            console.log(`Setting language to ${lang}`);
            this.translate.use(lang);
        })
    }
}