import { CommonModule } from '@angular/common';
import { Component, computed, input } from '@angular/core';
import { Option } from "../../../interfaces";
import { TemplateData } from "../../../interfaces";
import { FormsModule } from '@angular/forms';
import { TranslateDirective, TranslatePipe } from '@ngx-translate/core';
import { fb } from '../util';

@Component({
    selector: 'template-preview',
    templateUrl: './preview.html',
    styleUrls: ['../shared.scss'],
    styles: [`.body {white-space-collapse: preserve;}`],
    imports: [CommonModule, FormsModule, TranslatePipe, TranslateDirective],
})
export class PreviewComponent {
    public readonly data = input.required<TemplateData>();
    public readonly options = input.required<Option[]>();
    
    public get header() {
        return this.replacePlaceholders(
            this.data().components.header?.text ?? '', 
        );
    }

    public get body() {
        return this.replacePlaceholders(
            this.data().components.body?.text ?? '', 
            'TEMPLATE_EDITOR.PREVIEW.DEFAULT_BODY'
        );
    }

    public get buttons() {
        return this.data().components.buttons?.buttons ?? [];
    }

    public get footer() {
        return this.data().components.footer?.text ?? '';
    }

    private replacePlaceholders(text?: string, fallback?: string): string {
        if (!text && fallback) {
            text = fallback;
        }
        let result = text ?? '';
        this.options().forEach(option => {
            const regex = new RegExp(`{{\\s*${option.value}\\s*}}`, 'g');
            result = result.replace(regex, option.example || option.label);
        });
        return result;
    }
}