import { CommonModule } from "@angular/common";
import { Component, ViewEncapsulation, input, output } from "@angular/core";
import { BaseComponent } from "../base.component";
import { TranslateDirective } from '@ngx-translate/core';

@Component({
    selector: 'vierkant-confirmation',
    templateUrl: './confirmation.html',
    styleUrls: ['./confirmation.scss', '../buttons.scss'],
    encapsulation: ViewEncapsulation.None,
    imports: [CommonModule, TranslateDirective],
})
export class Confirmation extends BaseComponent {
    public readonly message = input<string>();
    public readonly confirmText = input<string>("TEMPLATE_EDITOR.BUTTONS.CANCEL");
    public readonly cancelText = input<string>("TEMPLATE_EDITOR.BUTTONS.CONFIRM");
    public readonly onCancel = output<void>({ alias: 'cancel' });
    public readonly onConfirm = output<void>({ alias: 'confirm' });

    cancel() {
        this.onCancel.emit();
    }

    confirm() {
        this.onConfirm.emit();
    }
}   